public class Solution {
    public bool IsAnagram(string s, string t) {
        // Your solution here
        Dictionary<char, int> charMap = new Dictionary<char, int>();

        for(int i = 0; i<s.Length;i++){
            if(charMap.ContainsKey(s[i])){
                charMap[s[i]]++;
            }
            else{
                charMap[s[i]]=1;
            }
        }

        for(int i =0; i<t.Length; i++){

            if(!charMap.ContainsKey(t[i])){
                return false;
            }
            else{
                charMap[t[i]]--;
            }
        }

        foreach  (var kvp in charMap){
            if(kvp.Value !=0){
                return false;
            }
        }

        return true;
    }
}

class Program {
    static void Main() {
        var sol = new Solution();
        Console.WriteLine(sol.IsAnagram("anagram", "nagaram")); // true
        Console.WriteLine(sol.IsAnagram("rat", "car"));         // false
        Console.WriteLine(sol.IsAnagram("a", "ab"));            // false
    }
}

