public class Solution {
    public IList<IList<string>> GroupAnagrams(string[] strs) {
        // Your solution here
        IList<IList<string>> result = [];

        Dictionary<string, IList<string>> stringMap = new Dictionary<string, IList<string>>();

        for (int i =0; i<strs.Length; i++){

            string sorted = SortString(strs[i]);

            if(stringMap.ContainsKey(sorted)){
                stringMap[sorted].Add(strs[i]);
            }
            else{
                stringMap.Add(sorted, [strs[i]]);
            }
        }

        foreach(var kvp in stringMap){
            result.Add(kvp.Value);
        }

        return result;
    }

    public static string SortString(string str){
        char[] chars = str.ToCharArray();
        Array.Sort(chars);
        return new string(chars);
    }
}

class Program {
    static void Main() {
        var sol = new Solution();
        var r = sol.GroupAnagrams(new string[]{"eat","tea","tan","ate","nat","bat"});
        foreach (var group in r)
            Console.WriteLine("[" + string.Join(",", group) + "]");
    }
}

