        for (int i = 0; i < nums.Length; i++)
        {
            numMap[nums[i]] = i;
        }

        for(int i = 0; i<nums.Length; i++)
        {
            if(numMap.TryGetValue(target-nums[i], out int j) && (i!=j))
            {
               result[0]=i;
               result[1]=j;
