public class Solution {
    public int[] TopKFrequent(int[] nums, int k) {
        // Your solution here

        // find freqMap
        var freqMap = GetFreqMap(nums);

        // get freqBuckets
        var freqBuckets = GetFreqBuckets(freqMap, nums.Length);

        // get the k most frequent elements
        List<int> resultList = new List<int>();


        for (int i = freqBuckets.Length-1; i >= 0; i--) {

            if(resultList.Count==k){
                    break;
            }

            List<int> bucket = freqBuckets[i];

            if(bucket == null){
                continue;
            }

            for (int j = 0; j < bucket.Count; j++)
            {
                if(resultList.Count==k){
                    break;
                }
                else{
                    resultList.Add(bucket[j]);
                } 
            }
        }

        return resultList.ToArray();
    }

    public static Dictionary<int, int> GetFreqMap(int[] nums){

        Dictionary<int, int> freqMap = new Dictionary<int, int>();

        foreach (int n in nums) {
            freqMap[n] = freqMap.GetValueOrDefault(n) + 1;
        }

        return freqMap;
    } 

    public static List<int>[]  GetFreqBuckets(Dictionary<int, int> freqMap, int maxPossibleFreq){

        List<int>[] buckets = new List<int>[maxPossibleFreq];

        foreach (var kvp in freqMap) {
            // for key find value; that value is freq; this key gets added to array at index value-1 
            buckets[kvp.Value-1]??=[];
            buckets[kvp.Value-1].Add(kvp.Key);
        }

        return buckets;
    }
}

